-- Наполнение FAQ вопросами по новому разделу «Патчи» и статистике места на диске в админке
INSERT INTO faq_items (question, answer, sort_order) VALUES
('Как устроен раздел «Патчи»?', '<p>Раздел «Патчи» — это общее файловое дерево клиентского патча, отдельное для каждого сервера (С4х1, HFx3 old, HF new). Дерево организовано по фиксированным папкам, которые соответствуют структуре клиента игры: <strong>animations</strong>, <strong>data</strong>, <strong>l2text</strong>, <strong>maps</strong>, <strong>staticmeshes</strong>, <strong>System</strong>, <strong>System_eng</strong>, <strong>systextures</strong>, <strong>textures</strong>.</p>
<p>Просматривать дерево и скачивать любой файл может любой участник команды. Загружать файлы, удалять их, привязывать к задачам и управлять папками может администратор или участник с правом полного редактирования задач.</p>
<p><strong>Как загрузить файлы:</strong> выберите сервер, при необходимости выберите задачу в списке над деревом (тогда файлы автоматически прикрепятся к ней), затем перетащите папку прямо на нужную корневую папку в дереве — вложенная структура сохранится. Во время загрузки виден прогресс-бар, загрузку можно отменить.</p>
<p>Рядом с названием сервера есть кнопка «+» — она добавляет собственную корневую папку сверх стандартных. Удалить такую папку можно только если в ней не осталось ни одного файла.</p>', 21),
('Как прикрепить или открепить файл патча к задаче?', '<p>Привязать файл, который уже лежит в дереве раздела «Патчи», к задаче можно без повторной загрузки: выберите задачу в выпадающем списке над деревом, наведите курсор на нужный файл — справа появится иконка скрепки. Клик прикрепляет файл к выбранной задаче, повторный клик — открепляет.</p>
<p>Один файл может быть одновременно прикреплён сразу к нескольким задачам — привязки не заменяют друг друга, а дополняются. Если файл по тому же пути будет загружен заново с более поздними правками, в дереве останется только последняя версия, но все прежние привязки к задачам за ним сохранятся.</p>
<p>Если в задаче есть прикреплённые файлы патча, рядом со списком задач в разделе «Патчи» появляется кнопка «Скачать файлы задачи» — она собирает все привязанные к этой задаче файлы в один zip-архив.</p>', 22),
('Где посмотреть, сколько места занято на сервере?', '<p>Во вкладке «Файлы» в панели администратора (кнопка «Файлы» наверху) над списком всех загруженных вложений показывается статистика места на диске сервера: сколько уже занято, сколько всего и сколько осталось свободным — в виде полосы загрузки.</p>
<p>Полоса меняет цвет в зависимости от заполненности: обычный цвет при небольшой загрузке, жёлтый при 75% и выше, красный при 90% и выше — это подсказывает, что пора освободить место или расширить диск.</p>', 23);